import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

class SpacingAroundColonInAnnotationTest {
    private val spacingAroundColonRuleAssertThat = assertThatRule { SpacingAroundColonRule() }

    @Test
    fun `Given an annotation with no spacing around the colon then no violations should be reported`() {
        val code =
            """
            @file:JvmName("Foo")
            class Example(@field:Ann val foo: String, @get:Ann val bar: String)
            class Example {
                @set:[Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            fun @receiver:Fancy String.myExtension() { }
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an annotation with spacing before the colon then a violation should be reported`() {
        val code =
            """
            @file :JvmName("Foo")
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolation(1, 6, "Unexpected spacing before \":\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given an annotation with spacing after the colon then a violation should be reported`() {
        val code =
            """
            @file: JvmName("Foo")
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolation(1, 7, "Unexpected spacing after \":\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given an annotation with spacing before and after the colon then violations should be reported`() {
        val code =
            """
            @file : JvmName("Foo")
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo")
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 6, "Unexpected spacing before \":\""),
                LintViolation(1, 7, "Unexpected spacing after \":\""),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given an annotation entry with spacing before the colon then a violation should be reported`() {
        val code =
            """
            class Example {
                @set :[Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            """.trimIndent()
        val formattedCode =
            """
            class Example {
                @set:[Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolation(2, 10, "Unexpected spacing before \":\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given an annotation entry with spacing after the colon then a violation should be reported`() {
        val code =
            """
            class Example {
                @set: [Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            """.trimIndent()
        val formattedCode =
            """
            class Example {
                @set:[Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolation(2, 10, "Unexpected spacing after \":\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given an annotation entry with spacing before and after the colon then violations should be reported`() {
        val code =
            """
            class Example {
                @set : [Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            """.trimIndent()
        val formattedCode =
            """
            class Example {
                @set:[Inject VisibleForTesting]
                public var collaborator: Collaborator
            }
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(2, 9, "Unexpected spacing before \":\""),
                LintViolation(2, 10, "Unexpected spacing after \":\""),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given field annotation with spacing around the colon then violations should be reported`() {
        val code =
            """
            class Example(@field :Ann val foo: String, @get: Ann val bar: String)
            """.trimIndent()
        val formattedCode =
            """
            class Example(@field:Ann val foo: String, @get:Ann val bar: String)
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 22, "Unexpected spacing before \":\""),
                LintViolation(1, 50, "Unexpected spacing after \":\""),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given receiver annotation with spacing around the colon then violations should be reported`() {
        val code =
            """
            fun @receiver :Fancy String.myExtension() { }
