import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.LintViolation
import org.junit.jupiter.api.Test

/**
 * Comprehensive test for annotation colon spacing covering issue #2093.
 * Tests that spacing is not allowed around colons in annotations and annotation entries.
 */
class AnnotationColonSpacingComprehensiveTest {
    private val spacingAroundColonRuleAssertThat = assertThatRule { SpacingAroundColonRule() }

    @Test
    fun `Given file annotations with various spacing patterns then violations are detected and fixed`() {
        val code =
            """
            @file:JvmName("Foo1")
            @file :JvmName("Foo2")
            @file: JvmName("Foo3")
            @file : JvmName("Foo4")
            """.trimIndent()
        val formattedCode =
            """
            @file:JvmName("Foo1")
            @file:JvmName("Foo2")
            @file:JvmName("Foo3")
            @file:JvmName("Foo4")
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(2, 7, "Unexpected spacing before \":\""),
                LintViolation(3, 7, "Unexpected spacing after \":\""),
                LintViolation(4, 7, "Unexpected spacing before \":\""),
                LintViolation(4, 8, "Unexpected spacing after \":\""),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given annotation entries with various spacing patterns then violations are detected and fixed`() {
        val code =
            """
            class Example {
                @set:[Inject VisibleForTesting]
                var v1: String = ""

                @set :[Inject VisibleForTesting]
                var v2: String = ""

                @set: [Inject VisibleForTesting]
                var v3: String = ""

                @set : [Inject VisibleForTesting]
                var v4: String = ""
            }
            """.trimIndent()
        val formattedCode =
            """
            class Example {
                @set:[Inject VisibleForTesting]
                var v1: String = ""

                @set:[Inject VisibleForTesting]
                var v2: String = ""

                @set:[Inject VisibleForTesting]
                var v3: String = ""

                @set:[Inject VisibleForTesting]
                var v4: String = ""
            }
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(5, 10, "Unexpected spacing before \":\""),
                LintViolation(8, 10, "Unexpected spacing after \":\""),
                LintViolation(11, 10, "Unexpected spacing before \":\""),
                LintViolation(11, 11, "Unexpected spacing after \":\""),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given field and get annotations with spacing then violations are detected and fixed`() {
        val code =
            """
            class Example(
                @field :Ann val foo: String,
                @get: Ann val bar: String,
                @get : Ann val baz: String
            )
            """.trimIndent()
        val formattedCode =
            """
            class Example(
                @field:Ann val foo: String,
                @get:Ann val bar: String,
                @get:Ann val baz: String
            )
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(2, 12, "Unexpected spacing before \":\""),
                LintViolation(3, 10, "Unexpected spacing after \":\""),
                LintViolation(4, 10, "Unexpected spacing before \":\""),
                LintViolation(4, 11, "Unexpected spacing after \":\""),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given receiver annotations with spacing then violations are detected and fixed`() {
        val code =
            """
            fun @receiver :Fancy String.ext1() { }
            fun @receiver: Fancy String.ext2() { }
            fun @receiver : Fancy String.ext3() { }
            """.trimIndent()
        val formattedCode =
            """
            fun @receiver:Fancy String.ext1() { }
            fun @receiver:Fancy String.ext2() { }
            fun @receiver:Fancy String.ext3() { }
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code)
            .hasLintViolations(
                LintViolation(1, 14, "Unexpected spacing before \":\""),
                LintViolation(2, 14, "Unexpected spacing after \":\""),
                LintViolation(3, 14, "Unexpected spacing before \":\""),
                LintViolation(3, 15, "Unexpected spacing after \":\""),
            ).isFormattedAs(formattedCode)
    }

    @Test
    fun `Given correctly formatted annotations without spacing then no violations are reported`() {
        val code =
            """
            @file:JvmName("Foo")

            class Example(
                @field:Ann val foo: String,
                @get:Ann val bar: String
            ) {
                @set:[Inject VisibleForTesting]
                var collaborator: Collaborator = TODO()
            }

            fun @receiver:Fancy String.myExtension() { }
            """.trimIndent()
        spacingAroundColonRuleAssertThat(code).hasNoLintViolations()
    }
}
